import type { ScenarioQuestion } from "./types";

function q(id: string, group: string, sub: string, fmt: "scenario" | "behavioral" | "situational" | "star", scenario: string, question: string, answer: string, feedback: string, diff: "beginner" | "intermediate" | "advanced"): ScenarioQuestion {
  return { id, formatType: fmt, categoryGroup: group, subcategory: sub, scenarioPrompt: scenario, question, exampleAnswer: answer, feedback, difficulty: diff };
}

export const expandedBatch2: ScenarioQuestion[] = [
  q("sq-ex2-1","interview_preparation","behavioral","behavioral","You discover a patient is being discharged without a follow-up appointment scheduled.","How would you ensure a safe discharge transition?","I would pause the discharge process and contact the case manager or physician's office to schedule a follow-up appointment. I would also verify the patient has written discharge instructions, understands their medications, and has access to transportation. Discharge without follow-up increases readmission risk.","Catching discharge gaps prevents readmissions and improves outcomes.","beginner"),
  q("sq-ex2-2","interview_preparation","behavioral","behavioral","A patient's family accuses you of neglect because their call light was not answered quickly.","How would you respond to an accusation of neglect?","I would listen without becoming defensive, apologize for the delay, and explain what was happening during the time. I would assess and address the patient's needs immediately. I would document the interaction and discuss strategies for faster call light response with my team. If the family wants to escalate, I would provide patient relations information.","Active listening and non-defensive response to accusations.","intermediate"),
  q("sq-ex2-3","interview_preparation","clinical_judgment","scenario","A patient with pneumonia develops a sudden drop in oxygen saturation to 82% despite being on 4L nasal cannula.","What would you do for this acutely desaturating patient?","I would immediately increase oxygen delivery—switching to a non-rebreather mask at 15L. I would assess breath sounds, respiratory effort, and level of consciousness. I would elevate the head of the bed, call the rapid response team if the patient is not improving quickly, and prepare for possible intubation. I would obtain an ABG and portable chest X-ray.","Escalating oxygen delivery and activating emergency response for acute desaturation.","advanced"),
  q("sq-ex2-4","interview_preparation","clinical_judgment","scenario","A post-thyroidectomy patient complains of tingling around their lips and fingertips.","What complication might this indicate?","Perioral and fingertip tingling after thyroidectomy could indicate hypocalcemia from inadvertent damage to the parathyroid glands. I would check for positive Chvostek's and Trousseau's signs, obtain a stat serum calcium level, have IV calcium gluconate available, and notify the surgeon immediately. Severe hypocalcemia can lead to laryngospasm and cardiac arrhythmias.","Recognition of post-thyroidectomy complications and appropriate diagnostic testing.","advanced"),
  q("sq-ex2-5","interview_preparation","scenario_responses","scenario","A patient who is being treated for alcohol withdrawal starts hallucinating and becomes extremely agitated.","How would you manage a patient experiencing delirium tremens?","I would ensure safety first—calling for help, removing dangerous objects, and staying with the patient. I would assess vital signs and CIWA score, administer benzodiazepines per protocol, provide a calm environment with reduced stimulation, and monitor continuously. DTs are a medical emergency with a significant mortality rate if undertreated.","Recognition of DTs as a medical emergency requiring aggressive treatment.","advanced"),
  q("sq-ex2-6","interview_preparation","star_examples","star","Describe a clinical experience that shaped your nursing philosophy.","What experience most influenced your approach to nursing?","During my community health rotation, I provided wound care to a homeless patient at a free clinic. Despite living on the street, he was meticulous about trying to keep his wound clean. This experience taught me that every patient is doing their best with what they have, and my role is to meet them where they are without judgment. It shaped my commitment to patient-centered, compassionate care regardless of circumstances.","Authentic personal reflection that reveals nursing values.","beginner"),
  q("sq-ex2-7","interview_preparation","common_nursing_interview","behavioral","The interviewer asks: 'Tell me about your clinical rotations.'","How would you summarize your clinical experience effectively?","I completed rotations across medical-surgical, pediatrics, obstetrics, mental health, community health, and a capstone in the ICU. My strongest experience was in medical-surgical nursing where I managed up to four patients independently. I developed skills in medication administration, wound care, patient education, and interdisciplinary collaboration. My ICU capstone gave me experience with critical care monitoring and ventilator management.","Organized overview highlighting breadth and depth of clinical training.","beginner"),
  q("sq-ex2-8","interview_preparation","difficult_interviewer","scenario","The interviewer asks you an illegal question about your family plans.","How would you handle an inappropriate interview question?","I would redirect the conversation without directly addressing the inappropriate question. I might say, 'I am fully committed to this position and prepared to fulfill all job requirements. I am excited about the opportunity to contribute to your team.' If the question made me uncomfortable about the workplace culture, I would consider whether this is the right environment for me.","Professional redirection without confrontation.","advanced"),
  q("sq-ex2-9","interview_preparation","panel_interview","scenario","During a panel interview, one panel member seems to disagree with everything you say.","How would you handle a challenging panel member?","I would not take it personally—they may be testing my resilience or playing devil's advocate. I would acknowledge their perspective, provide additional reasoning for my position, and remain professional. I would maintain eye contact with all panel members and not let one difficult person throw me off my game.","Resilience under pressure and professional composure.","advanced"),
  q("sq-ex2-10","workplace_scenarios","prioritization","scenario","A patient's family insists their loved one needs a bath right now, but you have medications due for three other patients.","How would you handle conflicting care priorities?","I would acknowledge the family's request and explain, 'I understand the bath is important. I have some time-sensitive medications to give right now, but I will have the CNA assist with the bath in the next 30 minutes, or I can help as soon as I finish these medications.' I would delegate the bath to the CNA if appropriate and prioritize the medications.","Time-critical tasks over comfort tasks with clear communication.","beginner"),
  q("sq-ex2-11","workplace_scenarios","prioritization","scenario","You have a patient with low blood sugar, a patient with chest pain, and a patient requesting a bedpan simultaneously.","How do you triage these three needs?","Chest pain is the highest priority as it could indicate MI. I would assess that patient first while calling for help. I would ask a CNA to assist with the bedpan. Once the chest pain patient is being managed, I would treat the hypoglycemia, which is also urgent. The bedpan request is important for dignity but not life-threatening.","ABC priorities with effective delegation for non-urgent needs.","beginner"),
  q("sq-ex2-12","workplace_scenarios","delegation","scenario","A CNA reports that a patient's blood glucose is 55 mg/dL.","What would you delegate versus do yourself?","I would go to the patient immediately to assess them personally—assessing a patient and administering treatment is within the RN scope. I would ask the CNA to bring juice or glucose tablets while I assess the patient. I would administer the glucose, recheck in 15 minutes, and notify the provider. I would not delegate the assessment or treatment decision to the CNA.","RN must assess and treat; CNA can assist with supplies.","beginner"),
  q("sq-ex2-13","workplace_scenarios","patient_safety","scenario","A confused patient keeps removing their oxygen and pulling at their IV line.","How would you maintain safety for a confused patient who is disrupting their treatment?","I would assess the cause of confusion and address reversible factors. I would use the least restrictive interventions first: repositioning tubing, covering IV sites, providing a sitter, reorienting the patient, and using bed alarms. I would consider mittens only if other measures fail and with a physician order. I would never restrain without proper authorization and would reassess frequently.","Least restrictive interventions first, with proper authorization for restraints.","intermediate"),
  q("sq-ex2-14","workplace_scenarios","medication_error","scenario","A nurse reports to you that she accidentally gave a double dose of metoprolol to a patient.","How would you respond as the charge nurse to this medication error report?","I would immediately assess the patient's vital signs, focusing on heart rate and blood pressure. I would notify the physician and anticipate monitoring for bradycardia and hypotension. I would ensure the nurse files an incident report and provide emotional support—medication errors are stressful. I would review the circumstances to identify contributing factors without assigning blame.","Patient assessment first, supportive error management, system review.","intermediate"),
  q("sq-ex2-15","workplace_scenarios","handoff_communication","scenario","During bedside handoff, you notice a medication hanging that was not mentioned in the verbal report.","How would you address an unmentioned medication during handoff?","I would immediately ask the outgoing nurse about the medication: what it is, when it was started, and the indication. I would verify it against the current orders. This is one of the benefits of bedside handoff—catching discrepancies in real time. I would ensure the medication is documented properly and included in the plan of care.","Bedside handoff catches discrepancies that verbal-only handoff may miss.","beginner"),
  q("sq-ex2-16","workplace_scenarios","difficult_coworkers","scenario","A colleague routinely makes comments about your weight or appearance.","How would you address personal comments from a coworker?","I would address it directly: 'I would appreciate if you would not comment on my appearance. It makes me uncomfortable.' If the behavior continued, I would document it and report it to my manager and HR as it could constitute harassment. Everyone has the right to work in an environment free from personal comments about their body.","Clear boundary-setting and escalation for harassment.","intermediate"),
  q("sq-ex2-17","workplace_scenarios","interdisciplinary_communication","scenario","The respiratory therapist makes ventilator changes without updating the nursing care plan.","How would you address uncoordinated care changes?","I would speak with the RT directly: 'I noticed the ventilator settings were changed. Can you update me on the rationale so I can monitor the patient's response and update the care plan?' I would suggest establishing a communication protocol where RT changes are communicated to the bedside nurse in real time.","Collaborative communication protocols improve care coordination.","intermediate"),
  q("sq-ex2-18","clinical_transition","first_shift","scenario","You are assigned to a dying patient on your first week and feel unprepared.","How would you provide end-of-life care as a new nurse?","I would ask for guidance from my preceptor or charge nurse. I would focus on comfort: pain management, oral care, positioning, and maintaining dignity. I would support the family by being present and offering pastoral or social work services. I would allow myself to feel the emotions that come with this experience while providing compassionate care.","Seeking guidance while providing basic comfort care shows maturity.","intermediate"),
  q("sq-ex2-19","clinical_transition","new_nurse_anxiety","scenario","You wake up before every shift with nausea and dread about going to work.","How would you address physical symptoms of work-related anxiety?","Physical symptoms like nausea before every shift suggest significant anxiety that needs attention. I would speak with my employee assistance program counselor, consider whether the specific unit or shift contributes to the anxiety, and discuss with my manager. I would practice stress-reduction techniques and assess whether the anxiety is affecting my patient care.","Physical symptoms of anxiety warrant professional support.","intermediate"),
  q("sq-ex2-20","clinical_transition","time_management","scenario","You spend too much time on one complex patient and neglect your other patients.","How would you prevent tunnel vision with a complex patient?","I would set time limits for each patient interaction and use a timer or alarm as a reminder. I would delegate monitoring tasks to support staff when I need to focus on the complex patient. I would do quick safety rounds on all patients before diving deep into any one patient's care. I would communicate with the charge nurse if one patient requires more time than my assignment allows.","Structured time allocation prevents tunnel vision.","intermediate"),
  q("sq-ex2-21","clinical_transition","documentation_challenges","scenario","You need to document a fall that happened when you were not in the room.","How would you document an unwitnessed patient event?","I would document it as an unwitnessed event, including: the time I found the patient, their position, their statements about what happened, my assessment findings (injuries, vital signs, neuro checks), interventions performed, and notifications made. I would not speculate about how the fall occurred. I would include quotes from the patient about the event.","Document objectively what you found and what the patient reported.","intermediate"),
  q("sq-ex2-22","professional_development","professional_boundaries","scenario","A patient asks you to recommend a specific physician outside the hospital for their ongoing care.","How would you handle a recommendation request?","I would explain that I cannot recommend specific physicians but can help them find resources. I would suggest they contact their insurance company for in-network providers, use the hospital's physician referral line, or ask their primary care provider for recommendations. Making personal recommendations could create liability issues.","Redirect to appropriate referral channels rather than personal recommendations.","beginner"),
  q("sq-ex2-23","professional_development","ethical_dilemmas","scenario","A mentally ill patient refuses psychiatric medication but is a danger to themselves.","How would you balance autonomy with safety for a psychiatric patient?","I would assess the patient's capacity to make medical decisions. If they lack capacity due to their mental illness, involuntary medication may be legally justified with proper authorization. I would follow facility policy for involuntary treatment, ensure proper documentation and physician orders, and continue to try therapeutic communication. Patient rights advocates should be involved.","Legal and ethical frameworks for involuntary treatment decisions.","advanced"),
  q("sq-ex2-24","professional_development","workplace_bullying","scenario","Your preceptor speaks negatively about you to other staff when you are not present.","How would you address a preceptor who talks about you behind your back?","I would address it directly with my preceptor in private: 'I have heard that there are concerns about my performance. I would appreciate hearing your feedback directly so I can improve.' If the behavior continued, I would request a meeting with my nurse educator to discuss the preceptor relationship and potentially request a change.","Direct communication about indirect behavior.","intermediate"),
  q("sq-ex2-25","professional_development","advocacy","scenario","A patient is being sent home with wound care supplies they cannot afford.","How would you advocate for a patient who cannot afford medical supplies?","I would contact social work to explore financial assistance programs. I would check if the hospital has a supply assistance program or charity care. I would contact the wound care company about patient assistance programs. I would educate the patient on affordable alternatives and ensure they have enough supplies to last until assistance is arranged.","Resource mobilization for patients facing financial barriers.","intermediate"),
  q("sq-ex2-26","professional_development","patient_communication","scenario","An elderly patient keeps forgetting what you told them about their medications.","How would you adapt teaching for a patient with memory difficulties?","I would use repetition, written instructions with large print, and involve family members in the teaching. I would teach one medication at a time and use visual aids. I would create a simple medication chart with pictures and connect medication times to daily routines. I would assess whether the memory difficulty is new and potentially clinically significant.","Adaptive teaching strategies for cognitive limitations.","beginner"),
  q("sq-ex2-27","career_navigation","job_offer_negotiation","scenario","You are offered a night shift position but strongly prefer day shift.","How would you negotiate shift preference as a new graduate?","I would express my enthusiasm for the position and ask about the timeline for transitioning to day shift. Most units require new graduates to start on nights. I would ask, 'Is there a specific timeframe after which I could request a shift change? How does the seniority-based scheduling work?' Understanding the path to days helps manage expectations.","Understanding organizational norms while expressing preferences professionally.","beginner"),
  q("sq-ex2-28","career_navigation","probation_period","scenario","You feel overwhelmed by the documentation system during your probation period.","How would you get up to speed on the electronic health record?","I would request additional EHR training sessions if available. I would practice during downtime, create personal tip sheets for common documentation tasks, and ask experienced nurses to show me their efficient charting strategies. I would use the EHR's help features and reach out to the clinical informatics team for personalized training.","Proactive learning of documentation systems through multiple channels.","beginner"),
  q("sq-ex2-29","career_navigation","performance_evaluation","scenario","Your evaluation is outstanding, and your manager asks what you need to continue growing.","How would you articulate your professional development needs?","I would identify specific areas for growth: 'I would love to develop my charge nurse skills and pursue my CCRN certification. I would appreciate mentoring from a senior nurse and support for attending a national conference this year.' Having specific, actionable requests shows self-awareness and initiative in career planning.","Specific growth requests demonstrate self-awareness and ambition.","beginner"),
  q("sq-ex2-30","career_navigation","career_advancement","scenario","You are torn between pursuing a clinical nurse specialist or nurse practitioner track.","How would you decide between CNS and NP career paths?","I would research the distinct roles: CNS focuses on system-wide quality improvement, education, and evidence-based practice within a specialty. NP focuses on direct patient care with prescriptive authority. I would shadow professionals in both roles, consider which daily activities appeal to me more, and assess job market demands in my area. Both require a master's degree but lead to very different practices.","Understanding the distinct roles of CNS versus NP for career alignment.","intermediate"),
  q("sq-ex2-31","interview_preparation","behavioral","behavioral","Tell me about a time you received praise for your work.","How do you handle positive recognition?","During my pediatric rotation, the parents of a child I cared for wrote a letter to the hospital praising my patience and attentiveness. I was honored but also took it as motivation to maintain that standard. I shared the credit with my team because quality care is always a team effort. Recognition reminds me why I chose nursing and reinforces the behaviors that make a difference.","Gracious acceptance while sharing credit with the team.","beginner"),
  q("sq-ex2-32","interview_preparation","behavioral","behavioral","Describe a time you had to deliver difficult news to someone.","How have you handled delivering bad news?","During clinical, I had to tell a patient that their lab results showed their diabetes was not well-controlled, and their treatment plan needed to change significantly. I prepared by reviewing the results and having resources available. I sat down, spoke honestly but compassionately, allowed them to express their feelings, and focused on actionable steps they could take.","Preparation, compassion, and focusing on forward steps.","intermediate"),
  q("sq-ex2-33","interview_preparation","clinical_judgment","scenario","A patient with cirrhosis develops abdominal distension, shortness of breath, and weight gain over 2 days.","What does this clinical picture suggest?","This presentation suggests ascites from decompensated liver cirrhosis. I would measure abdominal girth, assess respiratory compromise from diaphragm elevation, check fluid status with strict I&O, and notify the provider. I would anticipate orders for a paracentesis, albumin infusion, and diuretic therapy. I would monitor for signs of spontaneous bacterial peritonitis.","Recognition of ascites complications in cirrhosis.","advanced"),
  q("sq-ex2-34","interview_preparation","clinical_judgment","scenario","A patient on TPN develops hyperglycemia with blood glucose readings consistently above 250 mg/dL.","How would you manage hyperglycemia in a patient on TPN?","I would monitor blood glucose every 4-6 hours per protocol. I would notify the provider about the persistent hyperglycemia. I would anticipate an insulin drip or regular insulin added to the TPN bag. I would assess for signs of infection, which can worsen hyperglycemia, and review the TPN formula with the pharmacist for possible dextrose adjustments.","TPN-related hyperglycemia management and anticipating interventions.","intermediate"),
  q("sq-ex2-35","interview_preparation","scenario_responses","scenario","A mother brings her child to the ER and you suspect the child's injuries are not consistent with the explanation given.","How would you handle suspected child abuse?","I would document my objective findings carefully—describing injuries in detail without making accusations. I would report my concerns to the physician and follow mandatory reporting laws by contacting child protective services. I would treat the child's injuries compassionately. I would not confront the parent or tip them off about the report. All healthcare workers are mandated reporters.","Objective documentation, mandatory reporting, and non-confrontational approach.","advanced"),
  q("sq-ex2-36","interview_preparation","star_examples","star","Tell me about a time you improved a process or system.","Describe a quality improvement contribution you made.","I noticed that patient education materials in the cardiac unit were printed in English only, but 30% of our patients spoke Spanish. I proposed creating Spanish-language versions, worked with the translation services department, and developed bilingual education sheets for the five most common cardiac conditions. After implementation, patient comprehension scores for Spanish-speaking patients improved significantly.","Initiative to identify and solve a systemic gap with measurable outcomes.","intermediate"),
  q("sq-ex2-37","workplace_scenarios","prioritization","scenario","You are triaging in the emergency department and three patients arrive simultaneously: a child with a high fever, an adult with a laceration, and an elderly person with confusion.","How would you triage these three ED patients?","I would use the Emergency Severity Index. The elderly person with confusion could indicate stroke, sepsis, or other life-threatening conditions and needs immediate assessment. The febrile child needs prompt evaluation but is likely stable. The laceration, depending on severity, may be emergent or non-urgent. Context matters—I would do rapid assessments of each to determine the actual urgency.","Rapid assessment before assigning triage categories.","intermediate"),
  q("sq-ex2-38","workplace_scenarios","delegation","scenario","You need to delegate a blood glucose check to a new CNA who seems nervous about the task.","How would you support a nervous CNA with a delegated task?","I would offer to demonstrate the procedure first if they have not done it independently before. I would provide clear instructions, including where to find supplies, proper technique, documentation, and when to report results. I would check in after they complete the task to verify accuracy and build their confidence. Effective delegation includes ensuring competency.","Supportive delegation that builds team member competence.","beginner"),
  q("sq-ex2-39","workplace_scenarios","patient_safety","scenario","You discover that a patient has been sharing their prescription pain medication with their roommate.","How would you address patients sharing medications?","I would immediately stop the medication sharing and assess both patients. I would secure the medications and notify the provider for both patients. I would educate both patients about the dangers of sharing medications—different allergies, interactions, and dosing requirements. I would document the incident and ensure medications are properly locked and administered going forward.","Medication sharing is a serious safety issue requiring immediate intervention.","intermediate"),
  q("sq-ex2-40","workplace_scenarios","handoff_communication","scenario","You are transferring a patient to a long-term care facility and need to give report to a nurse you have never spoken with before.","How would you ensure a complete transfer to an external facility?","I would use a structured transfer form that includes diagnosis, treatment history, current medications, allergies, code status, functional status, skin assessment, and pending follow-ups. I would give a verbal SBAR report by phone, send copies of recent labs and imaging results, and include a medication reconciliation. I would verify the receiving nurse's name and document the transfer communication.","Comprehensive documentation and verbal communication for external transfers.","intermediate"),
  q("sq-ex2-41","workplace_scenarios","difficult_coworkers","scenario","A coworker frequently complains about management and tries to drag you into the negativity.","How would you handle a chronically negative coworker?","I would set boundaries by not engaging in chronic complaining. I would redirect conversations: 'I understand your frustration. Have you considered bringing this up with the manager directly?' I would not contribute to the negative culture but also would not lecture them. I would focus on maintaining my own positive attitude and seeking out supportive colleagues.","Boundary-setting and positive redirection without judgment.","beginner"),
  q("sq-ex2-42","clinical_transition","first_shift","scenario","You are assigned a patient with a tracheostomy on your second day and have limited tracheostomy care experience.","How would you manage a patient with a tracheostomy when you have limited experience?","I would immediately inform my preceptor about my limited experience and ask for guidance before performing trach care. I would review the tracheostomy care procedure, gather supplies, and ask to be supervised during the care. I would assess the tracheostomy site, patency, and the patient's respiratory status. I would ensure emergency equipment including a spare trach and obturator are at the bedside.","Honest disclosure of experience gaps and proactive resource-seeking.","intermediate"),
  q("sq-ex2-43","clinical_transition","new_nurse_anxiety","scenario","You keep replaying clinical scenarios in your head after work and cannot relax.","How would you manage rumination about clinical events?","I would set a designated debrief time after each shift—15 minutes to reflect, journal, and identify lessons learned. After that, I would consciously shift my attention to non-work activities. Physical exercise, mindfulness, and hobbies help break the rumination cycle. If rumination persists and affects my sleep or daily life, I would seek professional support through the EAP.","Structured reflection with intentional transition to personal time.","beginner"),
  q("sq-ex2-44","clinical_transition","time_management","scenario","You have a heavy medication pass at 9 AM with 15 medications across 5 patients.","How would you organize a complex medication pass efficiently?","I would prepare by pulling all medications in order of priority before starting rounds. I would organize them by patient and time. I would start with time-critical medications first. I would combine the med pass with brief assessments when possible. I would verify allergies and two patient identifiers for each. I would chart each medication immediately after administration to avoid backtracking.","Preparation and systematic organization for complex medication passes.","intermediate"),
  q("sq-ex2-45","clinical_transition","critical_thinking_drills","scenario","A patient's arterial blood gas shows pH 7.28, PaCO2 55, HCO3 24.","What does this ABG indicate and what would you do?","This ABG shows respiratory acidosis with no metabolic compensation. The elevated CO2 with normal HCO3 indicates an acute process—the patient is retaining CO2. I would assess respiratory status including rate, depth, effort, and level of consciousness. I would check for airway obstruction, medication-induced respiratory depression, or COPD exacerbation. I would notify the provider and prepare for possible BiPAP or intubation.","ABG interpretation with clinical correlation and intervention planning.","advanced"),
  q("sq-ex2-46","professional_development","professional_boundaries","scenario","A patient gives you an expensive watch as a thank-you gift.","How would you handle an expensive gift from a patient?","I would graciously decline and explain facility policy prohibiting gifts above a nominal value. I would suggest the patient express their gratitude through a letter to administration or a donation to the hospital foundation. If the patient insists, I would involve my charge nurse to help navigate the situation. I would document the offer per policy.","Warm decline with alternative gratitude channels.","beginner"),
  q("sq-ex2-47","professional_development","ethical_dilemmas","scenario","A colleague confides that they falsified their CPR certification because they could not afford the renewal class.","How would you handle knowledge of a colleague's falsified certification?","This is a patient safety issue that I cannot ignore. I would encourage my colleague to come forward to management themselves and offer to help find affordable CPR courses or employer-sponsored training. If they refused, I would need to report it, as patient safety depends on all team members having current certifications. Working without valid CPR certification is dangerous and illegal.","Patient safety over collegial loyalty—encourage self-reporting first.","advanced"),
  q("sq-ex2-48","professional_development","advocacy","scenario","You notice that the hospital food options do not accommodate patients with religious dietary restrictions.","How would you advocate for diverse dietary needs?","I would first address the immediate patient need by contacting dietary services and working with the kitchen to provide appropriate meals. I would document the gap and bring it to my manager's attention as a systemic issue. I would suggest the hospital develop a standard protocol for religious and cultural dietary accommodations. This falls under providing culturally competent care.","Immediate problem-solving plus systemic advocacy for improvement.","intermediate"),
  q("sq-ex2-49","career_navigation","probation_period","scenario","You receive conflicting instructions from your preceptor and the charge nurse during probation.","How would you handle conflicting guidance from supervisors?","I would clarify the discrepancy by saying, 'I received different guidance on this from my preceptor and the charge nurse. Could we clarify which approach is correct?' I would not choose one over the other without verification. I would check the policy if applicable. If the conflict persists, I would involve my nurse educator to establish consistent guidance.","Seeking clarification rather than choosing sides.","beginner"),
  q("sq-ex2-50","career_navigation","career_advancement","scenario","You want to attend a professional nursing conference but your manager says there is no budget.","How would you access professional development with limited funding?","I would explore alternatives: free virtual conferences, webinars, and online continuing education. I would apply for conference scholarships through professional organizations. I would propose attending as a poster presenter, which often reduces fees. I would check if the hospital has education funds through a different department. I would also suggest cost-sharing with colleagues.","Creative approaches to professional development despite funding limitations.","beginner"),
  q("sq-ex2-51","interview_preparation","behavioral","behavioral","Tell me about a mistake you made in clinical and what you learned from it.","Describe a clinical error and your learning process.","During medication preparation, I drew up the correct medication but in the wrong syringe size, which made it difficult to measure accurately. My preceptor caught the discrepancy before administration. I learned the importance of selecting appropriate equipment for each medication and now always verify syringe size as part of my preparation checklist. The experience made me more meticulous in all aspects of medication preparation.","Honest error disclosure with specific lesson learned and behavior change.","beginner"),
  q("sq-ex2-52","interview_preparation","behavioral","behavioral","Describe a time you showed empathy in a difficult situation.","How do you demonstrate empathy in clinical practice?","I cared for a homeless patient admitted for frostbite who was embarrassed about his hygiene. Rather than just providing clinical care, I helped him wash, found clean clothes from our supply closet, and sat with him while he ate. I asked about his story and connected him with our social worker. He later told me I was the first person in months who treated him like a human being.","Empathy through action, not just words.","beginner"),
  q("sq-ex2-53","interview_preparation","clinical_judgment","scenario","A patient receiving chemotherapy develops a temperature of 38.5°C and a WBC of 0.8.","What is the significance and what would you do?","This is neutropenic fever—a medical emergency in immunocompromised patients. Even low-grade fever with severe neutropenia requires immediate intervention. I would obtain blood cultures from two sites, start broad-spectrum antibiotics within one hour per protocol, implement neutropenic precautions, and monitor closely for sepsis. I would not wait to see if the fever resolves on its own.","Neutropenic fever is a medical emergency requiring immediate antibiotic therapy.","advanced"),
  q("sq-ex2-54","interview_preparation","clinical_judgment","scenario","An elderly patient on multiple medications develops confusion, dry mouth, constipation, and urinary retention.","What syndrome might this represent?","These symptoms together—confusion, dry mouth, constipation, and urinary retention—suggest anticholinergic toxicity. This is common in elderly patients on multiple medications with anticholinergic properties. I would review the medication list for anticholinergic burden, contact the pharmacist for a medication review, notify the provider, and monitor for worsening symptoms. Medication reconciliation is essential.","Recognition of anticholinergic syndrome in polypharmacy patients.","intermediate"),
  q("sq-ex2-55","interview_preparation","scenario_responses","scenario","A patient scheduled for discharge refuses to leave because they feel unsafe at home.","How would you respond when a patient expresses safety concerns about discharge?","I would take the concern seriously and explore what is making them feel unsafe—is it domestic violence, self-harm risk, or inability to care for themselves? I would involve social work immediately and delay the discharge until safety can be ensured. I would document the patient's stated concerns and the actions taken. Patient safety extends beyond the hospital walls.","Never dismiss safety concerns at discharge—investigate and involve social work.","intermediate"),
  q("sq-ex2-56","workplace_scenarios","prioritization","scenario","You have a patient coding in one room and a patient screaming in pain in another.","How would you manage these two emergencies?","The coding patient takes absolute priority as it is a life-threatening emergency. I would call the code and begin CPR if needed. I would ask another available nurse or the charge nurse to assess and medicate the patient in pain. Even severe pain, while important, is not immediately life-threatening. I would return to the pain patient as soon as the code is handled.","Life-threatening emergencies always take absolute priority.","advanced"),
  q("sq-ex2-57","workplace_scenarios","patient_safety","scenario","You notice that hand sanitizer dispensers on your unit are consistently empty.","How would you address a systemic infection control issue?","I would refill the dispensers I can access immediately. I would report the ongoing issue to my charge nurse and environmental services. I would document the pattern and bring it to the unit safety committee or infection control department. Hand hygiene is the most effective infection prevention measure, and empty dispensers are a system failure that needs a permanent fix.","Immediate fix plus systemic reporting for sustained improvement.","beginner"),
  q("sq-ex2-58","clinical_transition","critical_thinking_drills","scenario","A patient with no cardiac history has an ECG showing ST elevation in leads II, III, and aVF.","What does this ECG finding suggest?","ST elevation in leads II, III, and aVF indicates an inferior myocardial infarction affecting the right coronary artery territory. I would assess for symptoms including chest pain, diaphoresis, and nausea. I would notify the provider immediately, obtain a right-sided ECG to assess right ventricular involvement, prepare for emergent cardiac catheterization, and administer aspirin per protocol.","ECG pattern recognition for inferior MI with appropriate emergency response.","advanced"),
  q("sq-ex2-59","professional_development","patient_communication","scenario","A patient with a new colostomy is refusing to look at their stoma.","How would you support a patient adjusting to a colostomy?","I would normalize the emotional response and give them time. I would not force them to look at or touch the stoma. I would gradually involve them—first just being in the room during care, then looking, then touching, then participating in care. I would connect them with a wound/ostomy nurse and a support group of people with ostomies. Body image adjustment takes time.","Gradual exposure, emotional validation, and peer support.","intermediate"),
  q("sq-ex2-60","career_navigation","performance_evaluation","scenario","Your manager asks you to create a professional development plan for the coming year.","How would you create a meaningful professional development plan?","I would start with a self-assessment of my strengths and growth areas. I would set SMART goals: 'Complete ACLS certification by March, precept one new graduate by June, present a case study at a staff meeting by September, and begin studying for specialty certification by December.' I would include specific activities, timelines, and measurable outcomes. I would align my goals with both my career aspirations and unit needs.","SMART goals aligned with personal aspirations and organizational needs.","beginner"),
  q("sq-ex2-61","interview_preparation","behavioral","behavioral","Tell me about a time you failed at something.","How do you handle failure?","During my first attempt at IV insertion in clinical, I missed the vein and the patient winced in pain. I felt terrible. But I apologized sincerely, asked my preceptor to complete the insertion, and then practiced extensively on simulation arms after clinical hours. By the end of the rotation, my success rate was above 80%. I learned that failure is only permanent if you do not learn from it.","Specific failure, emotional honesty, and concrete recovery actions.","beginner"),
  q("sq-ex2-62","interview_preparation","clinical_judgment","scenario","A patient recovering from spinal surgery reports sudden loss of sensation in both legs and inability to move their toes.","What emergent complication do you suspect?","Sudden bilateral lower extremity weakness and sensory loss after spinal surgery suggests an epidural hematoma compressing the spinal cord—this is a neurosurgical emergency. I would perform an immediate neurological assessment, notify the surgeon STAT, and prepare for emergent return to the OR. Time is critical—permanent paralysis can result if decompression is delayed beyond a few hours.","Recognition of spinal emergency with time-critical surgical notification.","advanced"),
  q("sq-ex2-63","workplace_scenarios","delegation","scenario","Your unit is short-staffed and you have been asked to take on an additional patient, bringing your total to seven.","How would you manage an unsafe patient load?","I would document my concern in writing—an Assignment Despite Objection form if available. I would communicate specific patient acuity details to the charge nurse. I would prioritize the most critical patients, delegate as much as possible to support staff, and ask for additional help from float pool or agency nurses. I would focus on safety-critical tasks and defer non-urgent activities.","Documentation of unsafe assignments and systematic workload management.","intermediate"),
  q("sq-ex2-64","clinical_transition","first_shift","scenario","Your patient calls you by the wrong name repeatedly despite correction.","How would you handle being called the wrong name by a patient?","I would gently correct them each time without frustration: 'My name is actually [name]—no worries at all!' If the patient has cognitive impairment, I might write my name on the whiteboard. I would focus on providing excellent care regardless of what they call me. Sometimes patients confuse nurses' names, especially when they have multiple caregivers.","Grace and patience with repeated corrections.","beginner"),
  q("sq-ex2-65","professional_development","ethical_dilemmas","scenario","A terminally ill patient secretly asks you to remove their IV and stop all treatments.","How would you respond to a patient wanting to stop all treatment?","I would listen compassionately and assess whether this is an informed, voluntary decision. I would clarify their understanding of what stopping treatment means. I would notify the physician and involve the palliative care team. If the patient has decision-making capacity, they have the right to refuse treatment. I would ensure proper documentation, DNR/comfort care orders if appropriate, and family notification if the patient consents.","Patient autonomy in end-of-life decisions with proper process.","advanced"),
  q("sq-ex2-66","interview_preparation","common_nursing_interview","behavioral","The interviewer asks: 'How do you stay current with nursing practice?'","How do you maintain current nursing knowledge?","I use several strategies: I subscribe to nursing journals and follow evidence-based practice updates. I attend continuing education courses and webinars. I participate in unit-based education and journal clubs. I am a member of my specialty professional organization. I also learn from my colleagues daily—some of the best clinical education comes from working alongside experienced nurses.","Multiple ongoing learning strategies demonstrate commitment to excellence.","beginner"),
  q("sq-ex2-67","workplace_scenarios","medication_error","scenario","A patient's family member has been giving the patient unauthorized herbal supplements during their hospitalization.","How would you address unauthorized supplements in the hospital?","I would explain to the family that unapproved supplements can interact with prescribed medications and affect treatment outcomes. I would ask what supplements they have been giving and document them. I would consult with the pharmacist about potential interactions and notify the provider. I would secure the supplements and explain that all medications and supplements must be approved by the care team.","Addressing unauthorized substances with education rather than blame.","intermediate"),
  q("sq-ex2-68","clinical_transition","documentation_challenges","scenario","You need to document a sensitive conversation with a patient about end-of-life wishes.","How would you document end-of-life discussions?","I would document the conversation objectively: who was present, what was discussed, the patient's expressed wishes, their emotional state, and any decisions made. I would use direct quotes when possible. I would note if the patient has decision-making capacity. I would document referrals made (palliative care, chaplain, social work) and ensure the advance directive status is updated in the chart.","Thorough, sensitive documentation of end-of-life conversations.","intermediate"),
  q("sq-ex2-69","career_navigation","job_offer_negotiation","scenario","You are offered a position at a hospital that has poor online reviews from nurses.","How would you evaluate a hospital's workplace culture before accepting?","I would look beyond online reviews by visiting the unit during a typical shift, speaking with current staff if possible, and asking specific questions during the interview about nurse-to-patient ratios, turnover rates, and new graduate support. I would research the hospital's Magnet status, CMS quality ratings, and recent survey results. Online reviews can be skewed—I would form my own assessment.","Multi-source evaluation of workplace culture before making career decisions.","intermediate"),
  q("sq-ex2-70","workplace_scenarios","interdisciplinary_communication","scenario","The case manager is pushing for discharge but the patient's home situation has not been fully assessed.","How would you advocate for thorough discharge planning?","I would share my concerns with specific nursing assessment data: 'Based on my assessment, the patient cannot independently manage their medications, prepare meals, or ambulate safely. I believe we need a home assessment or transitional care placement before discharge.' I would request a team meeting to discuss the discharge plan and involve social work and physical therapy in the assessment.","Nursing assessment data as the foundation for discharge advocacy.","intermediate"),
  q("sq-ex2-71","interview_preparation","behavioral","behavioral","Tell me about your leadership style.","How would you describe your approach to leadership?","I believe in leading by example and empowering others. In my clinical groups, I naturally took on the role of organizing team activities and mentoring struggling classmates. I lead through competence, communication, and support rather than authority. I believe good leaders listen more than they talk and create environments where everyone feels safe to ask questions and contribute ideas.","Specific leadership examples rather than abstract descriptions.","beginner"),
  q("sq-ex2-72","interview_preparation","clinical_judgment","scenario","A patient with known liver disease develops asterixis and confusion.","What does this clinical picture suggest?","Asterixis (liver flap) combined with confusion in a liver disease patient suggests hepatic encephalopathy from elevated ammonia levels. I would obtain a stat ammonia level, assess the patient's neurological status using a standardized grading system, review their medications for any contributors, and anticipate orders for lactulose and rifaximin. I would assess for GI bleeding as a precipitating factor.","Recognition of hepatic encephalopathy with appropriate interventions.","advanced"),
  q("sq-ex2-73","workplace_scenarios","patient_safety","scenario","A patient on fall precautions insists on walking to the bathroom alone at night.","How would you prevent falls while respecting patient autonomy?","I would explain the fall risk clearly and collaborate on a plan: 'I want to make sure you can get to the bathroom safely. How about I leave your call light right here, and when you need to go, I will be here in less than a minute?' I would use a bedside commode as an alternative, keep the path well-lit, ensure non-slip footwear, and use a bed alarm as a backup.","Collaborative safety planning that respects autonomy.","beginner"),
  q("sq-ex2-74","clinical_transition","new_nurse_anxiety","scenario","You made a clinical decision independently for the first time and are second-guessing yourself.","How would you build confidence in independent clinical decision-making?","I would evaluate my decision objectively: Was it based on sound assessment? Did I follow policy? Was the outcome positive? If yes, I should trust my training. I would discuss the decision with my preceptor for validation or constructive feedback. I would keep a clinical confidence journal where I record good decisions to review when self-doubt creeps in.","Building confidence through objective self-evaluation and mentor validation.","beginner"),
  q("sq-ex2-75","professional_development","patient_communication","scenario","A patient is angry about their hospital bill and takes it out on you.","How would you de-escalate a patient angry about financial issues?","I would validate their frustration without taking it personally: 'I understand that healthcare costs are stressful, and I am sorry you are dealing with this on top of being ill.' I would not discuss billing specifics as it is outside my scope. I would connect them with the financial counselor or patient services department. I would continue providing excellent care regardless of their frustration.","Empathy, appropriate referral, and maintaining care quality despite patient frustration.","beginner"),
  q("sq-ex2-76","interview_preparation","scenario_responses","scenario","You accidentally enter a patient's room during an intimate moment with their partner.","How would you handle an awkward patient situation?","I would excuse myself immediately and apologize: 'I am so sorry for interrupting. I will give you some privacy and return in a little while.' I would knock and wait for permission before re-entering. I would not mention it to other staff or make the patient feel embarrassed. Patients have a right to privacy and normalcy even in the hospital.","Respecting patient dignity and privacy without overreacting.","beginner"),
  q("sq-ex2-77","workplace_scenarios","difficult_coworkers","scenario","A colleague takes personal credit for a team accomplishment during a staff meeting.","How would you handle misattributed credit in a team setting?","In the moment, I would calmly add context: 'I am glad you mentioned that project. It was really a team effort—several of us contributed to its success.' Privately, I would speak with the colleague about the importance of recognizing team contributions. If it became a pattern, I would ensure my own contributions are documented and visible to management through regular updates.","Gentle public correction and documentation of individual contributions.","intermediate"),
  q("sq-ex2-78","clinical_transition","critical_thinking_drills","scenario","A patient's urine output has been less than 30 mL/hour for the past 4 hours despite IV fluid administration.","What does declining urine output indicate?","Urine output less than 30 mL/hour (or 0.5 mL/kg/hour) suggests inadequate renal perfusion, which could indicate dehydration, cardiac failure, sepsis, or acute kidney injury. I would assess fluid status, check blood pressure and heart rate, review recent labs including creatinine and BUN, and notify the provider. I would anticipate a fluid challenge or change in management and continue strict I&O monitoring.","Low urine output as an indicator of systemic perfusion problems.","intermediate"),
  q("sq-ex2-79","professional_development","advocacy","scenario","You notice that visiting hours are too restrictive for a patient whose family can only visit in the evening.","How would you advocate for flexible visiting hours?","I would discuss the patient's needs with the charge nurse and see if an exception can be made. I would advocate for family presence as beneficial for patient recovery. If this is a systemic issue, I would bring it to the unit council or patient experience committee. I would ensure the patient's emotional and psychological needs are met regardless of visiting policy.","Individual exception-seeking plus systemic advocacy.","beginner"),
  q("sq-ex2-80","career_navigation","probation_period","scenario","A senior nurse tells you that you are not ready for independent practice yet, even though your preceptor disagrees.","How would you handle conflicting opinions about your readiness?","I would focus on objective measures—my competency checklist completion, preceptor evaluations, and patient outcomes. I would ask the senior nurse for specific examples of what concerns them so I can address those areas. I would not dismiss either opinion but would use both to inform my continued development. I would discuss the feedback with my nurse educator for perspective.","Using objective measures while respecting all feedback.","intermediate"),
  q("sq-ex2-81","interview_preparation","behavioral","behavioral","Describe how you handle working under pressure.","How do you perform during high-stress situations?","During a high-acuity clinical day, I had to manage a rapid response, a new admission, and a complex wound care procedure within two hours. I stayed calm by focusing on one task at a time, communicating clearly with my team, and using my priority framework. I asked for help when needed and completed all tasks safely. Afterward, I reflected on what worked well and what I could improve.","Specific high-pressure example with process and outcome.","intermediate"),
  q("sq-ex2-82","interview_preparation","clinical_judgment","scenario","A patient with type 1 diabetes is NPO for surgery and their blood glucose is 310 mg/dL.","How would you manage hyperglycemia in an NPO surgical patient?","I would notify the surgeon and anesthesiologist of the elevated glucose, as this may affect surgical timing. I would follow the facility's insulin sliding scale or correction protocol. I would monitor blood glucose more frequently—every 1-2 hours. I would ensure the patient has IV fluids running and monitor for DKA symptoms. I would communicate the glucose values to the surgical team before transport.","Preoperative glucose management and interdisciplinary communication.","intermediate"),
  q("sq-ex2-83","workplace_scenarios","handoff_communication","scenario","You receive a patient from the OR and the surgical team gives you a minimal handoff.","How would you ensure a thorough post-operative handoff?","I would use a structured post-operative handoff checklist: procedure performed, intraoperative complications, estimated blood loss, anesthesia type, current pain management, IV access and fluids, drain placement, and specific post-op orders. I would ask targeted questions about anything not covered. I would verify orders in the chart match the verbal report and assess the patient thoroughly upon arrival to the unit.","Structured post-op handoff with proactive questioning.","intermediate"),
  q("sq-ex2-84","clinical_transition","time_management","scenario","You find yourself charting the same information in multiple places in the electronic health record.","How would you reduce redundant documentation?","I would learn which fields auto-populate from other entries and use them efficiently. I would use copy-forward features where appropriate while ensuring accuracy. I would discuss with the clinical informatics team whether documentation workflows can be streamlined. I would create personal templates for frequently documented assessments. Redundant charting wastes time that could be spent with patients.","EHR efficiency skills and advocacy for workflow improvement.","beginner"),
  q("sq-ex2-85","professional_development","workplace_bullying","scenario","You overhear your name mentioned negatively in a conversation between nurses in the hallway.","How would you handle overhearing negative talk about yourself?","I would take a moment to compose myself before responding. If it felt appropriate, I would address it directly: 'I overheard my name. If there are concerns about my practice, I would appreciate hearing them directly so I can improve.' If I was not comfortable with direct confrontation, I would document it and discuss with my manager. I would not retaliate with gossip of my own.","Direct address or appropriate escalation without retaliation.","intermediate"),
  q("sq-ex2-86","interview_preparation","common_nursing_interview","behavioral","The interviewer asks: 'What type of unit environment works best for you?'","What work environment do you thrive in?","I thrive in collaborative environments where teamwork and mutual support are valued. I do well in settings that balance autonomy with mentorship—I want to grow independently while having experienced colleagues available for guidance. I appreciate units that prioritize patient safety culture, evidence-based practice, and professional development. I am also comfortable with fast-paced environments that challenge me clinically.","Specific environmental preferences aligned with professional nursing values.","beginner"),
  q("sq-ex2-87","workplace_scenarios","prioritization","scenario","At 6 AM, you are finishing your documentation and a patient calls reporting severe chest tightness.","How would you respond to a late-shift emergency?","I would immediately assess the patient regardless of my shift ending. Patient safety does not depend on shift schedules. I would assess vital signs, perform a focused cardiac assessment, start the chest pain protocol if indicated, and call for help. I would not leave the patient to complete my documentation. I would communicate with the oncoming nurse about the situation and stay until the patient is stable.","Patient care takes absolute priority over shift-end tasks.","beginner"),
  q("sq-ex2-88","clinical_transition","first_shift","scenario","You accidentally call a patient by the wrong name.","How would you recover from calling a patient the wrong name?","I would immediately apologize sincerely: 'I am so sorry, I called you the wrong name. You are Mrs. Williams, and I apologize for the mix-up.' I would verify I am in the correct room and reviewing the correct chart. I would double-check all my patient information to ensure no other mix-ups have occurred. While embarrassing, honest correction is far better than proceeding without verifying.","Immediate correction, sincere apology, and identity verification.","beginner"),
  q("sq-ex2-89","professional_development","ethical_dilemmas","scenario","You are asked to care for a patient whose personal beliefs conflict strongly with your own.","How would you provide care when personal beliefs conflict with a patient's?","I would separate my personal beliefs from my professional obligations. Every patient deserves compassionate, non-judgmental care regardless of their lifestyle, beliefs, or choices. I would focus on the patient as a person in need of care. If my beliefs genuinely prevented me from providing appropriate care, I would discuss reassignment with my charge nurse privately rather than providing substandard care.","Professional obligation to non-judgmental care with appropriate self-awareness.","intermediate"),
  q("sq-ex2-90","career_navigation","career_advancement","scenario","You are considering getting involved in nursing research as a bedside nurse.","How could you participate in research from the bedside?","I would look for opportunities to participate in unit-based quality improvement projects, which often use research methodology. I would volunteer as a data collector for ongoing studies. I would join my hospital's research council if one exists. I would identify a clinical question from my practice and work with a nurse researcher to investigate it. Even bedside nurses can contribute meaningfully to evidence-based practice development.","Multiple pathways to research involvement from the bedside.","intermediate"),
  q("sq-ex2-91","interview_preparation","behavioral","behavioral","Tell me about a time you resolved a conflict.","Describe your conflict resolution approach.","Two CNAs on my unit were having a scheduling dispute that was affecting team morale. I brought them together privately and facilitated a conversation where each person explained their needs. I helped them find a compromise that addressed both their concerns. I learned that most conflicts arise from unmet needs, and active listening is the most powerful conflict resolution tool.","Mediation skills with empathy and compromise-seeking.","intermediate"),
  q("sq-ex2-92","interview_preparation","scenario_responses","scenario","A patient asks you to help them write a complaint letter about a physician.","How would you respond to a request to help complain about a physician?","I would listen to the patient's concerns and validate their feelings. I would explain that while I cannot help write a complaint letter, I can connect them with patient relations who specializes in addressing concerns. I would also offer to relay their concerns to the nursing leadership. I would remain neutral about the physician while supporting the patient's right to voice their concerns.","Neutral support with appropriate referral to patient advocacy.","intermediate"),
  q("sq-ex2-93","workplace_scenarios","patient_safety","scenario","You notice a new construction area near the patient floor with dust and debris in the corridor.","How would you respond to environmental hazards from construction?","I would immediately close doors to patient rooms near the construction area to reduce airborne dust. I would report the hazard to facilities management and my charge nurse. For immunocompromised patients nearby, I would assess the need for HEPA filtration or room transfer. Construction near patient areas should follow infection control construction risk assessments.","Environmental safety awareness and immediate protective actions.","intermediate"),
  q("sq-ex2-94","clinical_transition","critical_thinking_drills","scenario","A patient's hemoglobin drops from 12 to 8 g/dL overnight without obvious external bleeding.","What would you suspect and investigate?","An acute hemoglobin drop without external bleeding suggests internal hemorrhage—GI bleeding is most common. I would assess for hidden blood loss: check stool for occult blood, monitor NG tube output if present, assess for abdominal distension or pain, check vital signs for hypovolemia (tachycardia, hypotension). I would notify the provider, prepare for possible blood transfusion, and type and crossmatch.","Systematic investigation of unexplained anemia with focus on GI bleeding.","intermediate"),
  q("sq-ex2-95","professional_development","patient_communication","scenario","A patient keeps pressing the call bell every 5 minutes for non-urgent requests.","How would you manage frequent non-urgent call bell use?","I would assess why the patient is pressing the bell frequently—anxiety, loneliness, unaddressed needs, or pain. I would address the root cause. I would implement proactive rounding every hour to anticipate needs. I would provide comfort items within reach and keep the patient informed about when I will return. I would not make the patient feel guilty for pressing the bell.","Root cause assessment and proactive rounding to reduce reactive calls.","beginner"),
  q("sq-ex2-96","interview_preparation","clinical_judgment","scenario","A patient has a wound VAC in place and the alarm indicates a loss of negative pressure.","How would you troubleshoot a wound VAC alarm?","I would first check for obvious issues: loose or leaking dressing seal, kinked tubing, full canister, or disconnected tubing. I would smooth the drape and apply additional adhesive to any air leak areas. I would ensure the canister is properly seated and not full. If I cannot resolve the alarm, I would contact the wound care nurse or the VAC manufacturer's support line while maintaining wound coverage.","Systematic troubleshooting of wound VAC issues.","intermediate"),
  q("sq-ex2-97","workplace_scenarios","delegation","scenario","You delegate glucose monitoring to a float CNA who is unfamiliar with your unit's glucometer.","How would you ensure competency when delegating to unfamiliar staff?","I would demonstrate the glucometer operation, verify the CNA's understanding through return demonstration, and provide clear parameters for reporting critical values. I would be available for questions and follow up on the first few readings to ensure accuracy. Delegating without verifying competency is unsafe, especially with unfamiliar staff.","Competency verification before delegation to unfamiliar staff.","beginner"),
  q("sq-ex2-98","clinical_transition","documentation_challenges","scenario","You need to document that a patient left the unit without permission.","How would you document a patient leaving the unit unsupervised?","I would document the time the patient was discovered missing, what I did to locate them, who was notified (charge nurse, physician, security), the patient's condition upon return, and any assessments performed. I would document the conversation with the patient about safety concerns. I would not use judgmental language like 'eloped' in some documentation systems—I would use factual descriptions.","Factual, non-judgmental documentation of safety events.","intermediate"),
  q("sq-ex2-99","career_navigation","performance_evaluation","scenario","Your peer evaluation feedback conflicts with your manager's feedback.","How would you reconcile conflicting feedback from different sources?","I would look for common themes in both evaluations. Where feedback conflicts, I would consider each source's perspective—peers see daily interactions while managers may see broader performance patterns. I would discuss the discrepancy with my manager to understand their perspective better. I would create an action plan that addresses the most critical feedback from both sources.","Synthesizing multiple feedback sources for comprehensive self-improvement.","intermediate"),
  q("sq-ex2-100","interview_preparation","behavioral","behavioral","Tell me about a time you had to make a quick decision under pressure.","Describe your decision-making process under time pressure.","During clinical, a patient's IV site suddenly swelled and the patient complained of pain. I immediately stopped the infusion, assessed the site for infiltration, removed the IV, applied a warm compress, and documented the incident. I then started a new IV in a different location and restarted the fluids. The whole process took about 10 minutes, and I kept the patient informed throughout.","Quick assessment, decisive action, and clear communication under pressure.","beginner"),
  q("sq-ex2-101","interview_preparation","clinical_judgment","scenario","A patient receiving a new medication develops Stevens-Johnson syndrome symptoms: widespread rash with blistering and mucosal involvement.","What would you do for suspected Stevens-Johnson syndrome?","SJS is a dermatologic emergency. I would stop the suspected causative medication immediately, notify the provider STAT, and prepare for possible ICU transfer. I would assess the extent of skin involvement, monitor vital signs, establish IV access for aggressive fluid resuscitation, manage pain, and protect exposed skin surfaces. This condition has significant mortality and requires urgent dermatology and possibly burn unit consultation.","Recognition of SJS as an emergency requiring immediate medication cessation.","advanced"),
  q("sq-ex2-102","workplace_scenarios","prioritization","scenario","You are managing post-op patients and receive notice that two of them need blood transfusions started at the same time.","How would you manage two simultaneous transfusions?","I cannot safely start two transfusions simultaneously as each requires a two-nurse verification and close monitoring during the first 15 minutes. I would start the transfusion for the patient with the lower hemoglobin first. I would ask another RN to start the second transfusion or schedule it 15-30 minutes later. Patient safety requires dedicated attention during transfusion initiation.","Safety limitations on simultaneous high-risk procedures.","intermediate"),
  q("sq-ex2-103","clinical_transition","new_nurse_anxiety","scenario","You hear experienced nurses discussing a clinical topic you know nothing about and feel inadequate.","How would you handle knowledge gaps you discover on the job?","I would note the topic and research it after the shift. I would not pretend to understand something I do not. I would consider asking a colleague to explain it: 'I have not encountered that before—can you tell me more?' Continuous learning is expected in nursing, and experienced nurses generally respect honest curiosity over pretended knowledge.","Embracing learning opportunities rather than hiding knowledge gaps.","beginner"),
  q("sq-ex2-104","professional_development","ethical_dilemmas","scenario","A patient's insurance denies coverage for a necessary procedure, and the patient cannot afford to pay out of pocket.","How would you navigate insurance denial affecting patient care?","I would involve the social worker and case manager to explore appeal options, financial assistance programs, and alternative treatment pathways. I would ensure the physician is aware of the denial so they can provide supporting documentation for an appeal. I would educate the patient about their right to appeal and connect them with patient advocacy resources. I would not let insurance bureaucracy go unchallenged when it affects patient care.","Multi-resource advocacy against insurance barriers.","intermediate"),
  q("sq-ex2-105","career_navigation","probation_period","scenario","You accidentally break a piece of equipment during your probation period.","How would you handle damaging equipment during probation?","I would immediately report the damage to my charge nurse and the appropriate department. I would not try to hide it or hope no one notices. I would take responsibility: 'I accidentally damaged this equipment while using it. I want to make sure it is repaired or replaced so patient care is not affected.' I would ask for additional training on the equipment if I was not using it properly.","Immediate honest reporting regardless of probation status.","beginner"),
  q("sq-ex2-106","interview_preparation","common_nursing_interview","behavioral","The interviewer asks: 'What do you know about our hospital?'","How would you demonstrate knowledge about the organization?","Before the interview, I researched your hospital thoroughly. I know you are a Level II trauma center with Magnet designation, which speaks to your commitment to nursing excellence. I read about your recent quality improvement initiatives in reducing hospital-acquired infections. I also noticed your strong new graduate residency program, which was a major factor in my decision to apply here.","Specific organizational knowledge demonstrates genuine interest and preparation.","beginner"),
  q("sq-ex2-107","workplace_scenarios","handoff_communication","scenario","You are giving report and the oncoming nurse asks about a detail you did not assess.","How would you handle being asked about something you missed during your shift?","I would be honest: 'I did not assess that specific thing during my shift. Let me check the chart quickly, or I can assess it now before I leave.' I would not fabricate information to avoid looking incompetent. I would also note the gap and add it to my future assessment routine to prevent missing it again.","Honesty about assessment gaps with immediate corrective action.","beginner"),
  q("sq-ex2-108","professional_development","advocacy","scenario","A patient with limited mobility has been in the same position for hours because the unit is short-staffed.","How would you prioritize repositioning in a busy environment?","I would reposition the patient immediately—pressure injuries can begin forming in as little as two hours. I would set a timer for repositioning every two hours and enlist any available team member to help. I would document the repositioning and skin assessment. I would report the staffing concern to the charge nurse, as inadequate staffing leading to delayed repositioning is a patient safety issue.","Prioritizing pressure injury prevention despite workload challenges.","beginner"),
  q("sq-ex2-109","interview_preparation","clinical_judgment","scenario","A patient with a central line develops sudden fever, chills, and rigors.","What complication would you suspect with a central line and sudden fever?","I would suspect a central line-associated bloodstream infection (CLABSI). I would draw blood cultures from the line and peripherally, assess the insertion site for signs of infection, and notify the provider immediately. I would anticipate the line being removed and cultured, and broad-spectrum antibiotics being started. I would monitor for sepsis and hemodynamic instability.","Recognition of CLABSI and appropriate culture collection.","intermediate"),
  q("sq-ex2-110","workplace_scenarios","patient_safety","scenario","A confused patient is wandering the hallways at night and approaching other patients' rooms.","How would you manage a wandering confused patient?","I would gently redirect the patient back to their room using a calm, non-confrontational approach. I would assess for causes of confusion (UTI, medications, delirium). I would implement safety measures: bed alarm, frequent checks, a sitter if available, and door monitoring. I would ensure the patient's basic needs are met (toileting, thirst, pain). I would update the care plan and notify the physician about the confusion.","Gentle redirection, root cause assessment, and safety implementation.","intermediate"),
  q("sq-ex2-111","interview_preparation","behavioral","behavioral","Tell me about a time when you disagreed with a policy but had to follow it anyway.","How do you handle policies you disagree with?","During clinical, I disagreed with a policy that limited visiting hours for ICU patients. I followed the policy while advocating for change through appropriate channels—I wrote a proposal for extended visiting hours supported by research showing family presence improves patient outcomes. I presented it to the unit council. Disagreement with policy should lead to advocacy for change, not non-compliance.","Compliance with appropriate advocacy through proper channels.","intermediate"),
  q("sq-ex2-112","clinical_transition","critical_thinking_drills","scenario","A diabetic patient develops warm, red, swollen skin on their lower leg with clear demarcation.","What condition do you suspect and what would you do?","The description suggests cellulitis—a bacterial skin infection common in diabetic patients due to impaired immune function and skin integrity. I would assess vital signs for sepsis indicators, measure and mark the borders of the redness for tracking, obtain blood cultures if the patient is febrile, and anticipate IV antibiotics. I would elevate the extremity and assess peripheral circulation.","Pattern recognition of cellulitis in a high-risk population.","intermediate"),
  q("sq-ex2-113","professional_development","patient_communication","scenario","A teenager patient refuses to talk to you and is clearly upset.","How would you build rapport with an uncommunicative teenager?","I would give them space while showing I am available. I might sit quietly in the room without forcing conversation, offer a distraction like music or magazines, and try again later. I would use open-ended questions and avoid sounding like an authority figure. I would validate their frustration: 'I get that being in the hospital is not where you want to be.' Building trust with teens takes patience.","Patience, non-judgmental presence, and age-appropriate communication.","beginner"),
  q("sq-ex2-114","career_navigation","career_advancement","scenario","You want to develop expertise in wound care nursing.","How would you develop a wound care specialization?","I would seek out wound care cases on my unit and request to be assigned to complex wound patients. I would shadow the wound care nurse specialist. I would pursue the Wound Care Certification through the WOCN society. I would attend wound care conferences and workshops. I would start a wound care resource binder for my unit. Developing expertise requires deliberate, focused effort over time.","Deliberate skill development through clinical exposure, certification, and mentorship.","intermediate"),
  q("sq-ex2-115","interview_preparation","star_examples","star","Tell me about a time you educated a patient effectively.","Describe a successful patient education experience.","I cared for a newly diagnosed heart failure patient who was overwhelmed by the dietary restrictions. Instead of handing them a pamphlet, I went through their typical daily meals together and identified specific swaps—using herbs instead of salt, reading nutrition labels for sodium content, and cooking techniques to improve flavor without added sodium. I created a personalized meal plan they could actually follow.","Individualized, practical education versus generic information delivery.","beginner"),
  q("sq-ex2-116","workplace_scenarios","medication_error","scenario","The pharmacy sends the wrong concentration of a medication and you catch it during your medication safety check.","How would you handle receiving the wrong medication from pharmacy?","I would hold the medication and contact the pharmacy immediately to report the discrepancy. I would not administer the medication. I would request the correct concentration and verify when it arrives. I would file an incident report about the pharmacy error so it can be investigated and prevented. I would document the catch and the delay in my patient's chart.","Medication safety checks catch system errors—report them for improvement.","beginner"),
  q("sq-ex2-117","clinical_transition","first_shift","scenario","You are asked to help with a procedure you observed in school but have never performed.","How would you handle being asked to perform a new procedure for the first time?","I would say, 'I observed this procedure during school but have not performed it independently. I would like to do it with supervision.' I would review the procedure quickly, gather supplies, and ask my preceptor to guide me through it. I would perform each step carefully, asking for confirmation at critical points. Everyone has a first time for every procedure.","Transparent about experience level while showing willingness to learn.","beginner"),
  q("sq-ex2-118","professional_development","ethical_dilemmas","scenario","A patient's health proxy makes a decision that seems contrary to what the patient would have wanted.","How would you address potentially inappropriate surrogate decisions?","I would first review the advance directive if one exists. I would facilitate communication between the proxy and the medical team about the patient's known wishes. If I believe the proxy is not acting in the patient's best interest, I would involve the ethics committee. The proxy's role is to represent the patient's wishes, not make decisions based on their own preferences.","Understanding of surrogate decision-making responsibilities and ethics committee role.","advanced"),
  q("sq-ex2-119","career_navigation","performance_evaluation","scenario","You are asked to set goals for the next evaluation period.","How would you set meaningful performance goals?","I would set goals that challenge me while being achievable: 'Achieve 100% compliance on hand hygiene audits. Complete at least 10 hours of continuing education in my specialty. Precept one new graduate nurse. Participate in one quality improvement project. Pursue my specialty certification exam.' I would align goals with both my career aspirations and the unit's priorities.","Specific, measurable goals aligned with personal and organizational objectives.","beginner"),
  q("sq-ex2-120","interview_preparation","behavioral","behavioral","Describe your approach to maintaining work-life balance.","How do you separate work from personal life?","I set clear boundaries: I do not check work email at home, I have a post-shift routine that helps me decompress—changing out of scrubs immediately, exercising, and spending time with people I care about. I schedule self-care activities and protect that time. I recognize that taking care of myself makes me a better nurse. I also have a support system of friends who understand nursing.","Specific, actionable strategies for maintaining boundaries.","beginner"),
];
